import React from "react";

export default function Contact({ onContactOpen }) {
  return (
    <section
      id="contact"
      className="section"
      style={{
        paddingLeft: "clamp(1.5rem, 8vw, 8rem)",
        paddingRight: "clamp(1.5rem, 8vw, 8rem)",
        borderTop: "1px solid #252A40"
      }}
    >
      <div style={{ maxWidth: "600px" }}>
        <p className="eyebrow mb-4">Contact</p>
        <h2
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontSize: "clamp(1.6rem, 3.5vw, 2.8rem)",
            fontWeight: 700,
            letterSpacing: "-0.025em",
            color: "#F0F0EC",
            lineHeight: 1.1,
            marginBottom: "1.25rem"
          }}
        >
          Ready to get started?<br />
          <span style={{ color: "#5B8DEF" }}>Let's talk.</span>
        </h2>

        <p
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "1rem",
            color: "#C8C8DC",
            lineHeight: 1.75,
            marginBottom: "2.5rem",
            maxWidth: "46ch"
          }}
        >
          Whether you want something built, need guidance, or just want to explore what AI can do for you — I'm one message away.
        </p>

        <button
          onClick={onContactOpen}
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: "0.5rem",
            fontFamily: "'Space Grotesk', sans-serif",
            fontWeight: 600,
            fontSize: "0.95rem",
            background: "#5B8DEF",
            color: "#F0F0EC",
            padding: "0.85rem 2rem",
            borderRadius: "0.375rem",
            border: "none",
            cursor: "pointer",
            transition: "opacity 0.15s ease"
          }}
          onMouseEnter={e => e.currentTarget.style.opacity = "0.88"}
          onMouseLeave={e => e.currentTarget.style.opacity = "1"}
        >
          Get in touch →
        </button>
      </div>

      {/* Footer */}
      <footer
        style={{
          marginTop: "6rem",
          paddingTop: "2rem",
          borderTop: "1px solid #252A40",
          display: "flex",
          flexWrap: "wrap",
          alignItems: "center",
          justifyContent: "space-between",
          gap: "1rem"
        }}
      >
        <p
          style={{
            fontFamily: "'JetBrains Mono', monospace",
            fontSize: "0.7rem",
            letterSpacing: "0.06em",
            color: "#3A3A5E"
          }}
        >
          Yair Berger · AI Engineer · Consultant · {new Date().getFullYear()}
        </p>
        {/* TODO: Replace # with your LinkedIn URL before launch */}
        <a
          href="#"
          target="_blank"
          rel="noopener noreferrer"
          style={{
            fontFamily: "'JetBrains Mono', monospace",
            fontSize: "0.7rem",
            letterSpacing: "0.06em",
            color: "#3A3A5E",
            textDecoration: "none",
            transition: "color 0.15s ease"
          }}
          onMouseEnter={e => e.currentTarget.style.color = "#8A8AB0"}
          onMouseLeave={e => e.currentTarget.style.color = "#3A3A5E"}
        >
          LinkedIn →
        </a>
      </footer>
    </section>
  );
}
